mapper.select:
select
    h.id, h.bill_no, h.organ_type, h.organ_id, h.organ_name,
    DATE_FORMAT(h.begin_time, '%Y-%m-%d') as begin_time,
    DATE_FORMAT(h.end_time, '%Y-%m-%d') as end_time,
    h.total_amount, h.is_paid,
    DATE_FORMAT(h.pay_time, '%Y-%m-%d') as pay_time,
    h.is_invoiced, h.invoice_code,
    DATE_FORMAT(h.invoice_time, '%Y-%m-%d') as invoice_time,
    h.creator, u.username as creator_name,
    DATE_FORMAT(h.create_time, '%Y-%m-%d') as create_time,
    h.last_update_by, h.last_update_time, h.remark,
    h.template_id, h.tenant_id, h.delete_flag
from jsh_reconciliation_head h
left join jsh_user u on h.creator = u.id and ifnull(u.status, 0) = 1
where ifnull(h.delete_flag, '0') != '1'

    and h.organ_type = #{organType}


    and h.organ_id = #{organId}


    and h.bill_no like CONCAT('%', #{billNo}, '%')


    and h.begin_time >= #{beginTime}


    and h.end_time <= #{endTime}


    and h.is_paid = #{isPaid}


    and h.is_invoiced = #{isInvoiced}


    and DATE_FORMAT(h.create_time, '%Y-%m') = #{createMonth}

order by h.id desc
limit #{offset}, #{rows}

select count(*) from jsh_reconciliation_head h
where ifnull(h.delete_flag, '0') != '1'

    and h.organ_type = #{organType}


    and h.organ_id = #{organId}


    and h.bill_no like CONCAT('%', #{billNo}, '%')


    and h.begin_time >= #{beginTime}


    and h.end_time <= #{endTime}


    and h.is_paid = #{isPaid}


    and h.is_invoiced = #{isInvoiced}


    and DATE_FORMAT(h.create_time, '%Y-%m') = #{createMonth}
